const items = $input.all();
const objectionMap = {};

items.forEach(item => {
  const objectionsField = item.json['Objections'];

  if (objectionsField && objectionsField.trim() !== '') {
    const objections = objectionsField.split(';');

    objections.forEach(obj => {
      const cleaned = obj.trim();
      if (cleaned && cleaned.toLowerCase() !== 'none raised') {
        objectionMap[cleaned] = (objectionMap[cleaned] || 0) + 1;
      }
    });
  }
});

// Sort by count descending and take top 10
const sorted = Object.entries(objectionMap)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10);

const timestamp = new Date().toISOString().slice(0, 19).replace('T', ' ');

return sorted.map(([objection, count]) => ({
  json: { 
    objection: objection,
    count: count,
    last_updated: timestamp
  }
}));

const items = $input.all();
const repStats = {};

items.forEach(item => {
  const rep = item.json['Sales Rep'] || 'Unassigned';

  if (!repStats[rep]) {
    repStats[rep] = {
      total_calls: 0,
      scores: [],
      high_intent: 0,
      buying_signals_count: 0,
      objections_count: 0,
      positive_sentiment: 0
    };
  }

  repStats[rep].total_calls++;

  const score = parseInt(item.json['Deal Score']) || 0;
  repStats[rep].scores.push(score);

  if (item.json['Intent Level'] === 'High') {
    repStats[rep].high_intent++;
  }

  if (item.json['Sentiment'] === 'Positive') {
    repStats[rep].positive_sentiment++;
  }

  // Count buying signals
  const signals = item.json['Buying Signals'] || '';
  if (signals && signals.trim() !== '') {
    repStats[rep].buying_signals_count += signals.split(';').filter(s => s.trim()).length;
  }

  // Count objections
  const objections = item.json['Objections'] || '';
  if (objections && objections.trim() !== '') {
    repStats[rep].objections_count += objections.split(';').filter(o => o.trim()).length;
  }
});

const timestamp = new Date().toISOString().slice(0, 19).replace('T', ' ');

return Object.entries(repStats).map(([rep, stats]) => {
  const avgScore = Math.round(
    stats.scores.reduce((a, b) => a + b, 0) / stats.scores.length
  );

  const highIntentPercent = ((stats.high_intent / stats.total_calls) * 100).toFixed(1);
  const positiveSentimentPercent = ((stats.positive_sentiment / stats.total_calls) * 100).toFixed(1);

  return {
    json: {
      sales_rep: rep,
      total_calls: stats.total_calls,
      avg_deal_score: avgScore,
      high_intent_calls: stats.high_intent,
      high_intent_percent: parseFloat(highIntentPercent),
      total_buying_signals: stats.buying_signals_count,
      total_objections: stats.objections_count,
      positive_sentiment_percent: parseFloat(positiveSentimentPercent),
      last_updated: timestamp
    }
  };
}).sort((a, b) => b.json.avg_deal_score - a.json.avg_deal_score);

const reps = $input.all();

if (!reps.length) return [];

// Sort reps by Avg Deal Score (descending)
const sortedReps = reps.sort((a, b) =>
  Number(b.json['Avg Deal Score']) - Number(a.json['Avg Deal Score'])
);

// Top performer = highest score
const topPerformer = sortedReps[0];

// Format team summary
const teamSummary = sortedReps.map((rep, idx) => `
${idx + 1}. ${rep.json['Sales Rep']}
   Calls: ${rep.json['Total Calls']} | 
   Avg Score: ${rep.json['Avg Deal Score']} | 
   High Intent: ${rep.json['High Intent %']}%
`).join('\n');

return [{
  json: {
    message: `📊 Weekly Sales Performance Report

🏆 TOP PERFORMER: ${topPerformer.json['Sales Rep']}
   • Avg Deal Score: ${topPerformer.json['Avg Deal Score']}/100
   • High Intent Calls: ${topPerformer.json['High Intent Calls']} (${topPerformer.json['High Intent %']}%)
   • Positive Sentiment: ${topPerformer.json['Positive Sentiment %']}%

📈 TEAM RANKING:
${teamSummary}

Full details in Sales Intelligence Hub → Rep Performance sheet.`
  }
}];

const items = $input.all();
const today = new Date();
const oneWeekAgo = new Date(today.getTime() - (7 * 24 * 60 * 60 * 1000));

const riskyDeals = items.filter(item => {
  const callDateStr = item.json['Call Date'];
  const callDate = new Date(callDateStr);

  const risks = item.json['Risks'] || '';
  const hasRisks = risks.trim() !== '' && risks.toLowerCase() !== 'none identified';

  const isRecent = callDate >= oneWeekAgo;

  return hasRisks && isRecent;
}).map(item => {
  const callDate = new Date(item.json['Call Date']);
  const daysSince = Math.floor((today - callDate) / (1000 * 60 * 60 * 24));

  const score = parseInt(item.json['Deal Score']);
  let status;
  if (score >= 70) {
    status = 'Active - Monitor';
  } else if (score >= 50) {
    status = 'Active - Requires Attention';
  } else {
    status = 'At Risk - Urgent Action';
  }

  return {
    json: {
      report_date: today.toISOString().split('T')[0],
      deal_name: item.json['Deal Name'],
      company: item.json['Company'],
      sales_rep: item.json['Sales Rep'],
      deal_score: item.json['Deal Score'],
      risks: item.json['Risks'],
      days_since_call: daysSince,
      status: status
    }
  };
}).sort((a, b) => a.json.deal_score - b.json.deal_score);

return riskyDeals;

const items = $input.all();

// Normalize + classify deals
const urgentDeals = [];
const attentionDeals = [];

items.forEach(item => {
  const status = item.json['Status'] || '';

  if (status.toLowerCase().includes('urgent')) {
    urgentDeals.push(item);
  } else if (
    status.toLowerCase().includes('attention') ||
    status.toLowerCase().includes('monitor')
  ) {
    attentionDeals.push(item);
  }
});

const reportDate = new Date().toLocaleDateString();

const formatDeals = (deals) =>
  deals.length
    ? deals.map(d => `
- ${d.json['Deal Name']} (${d.json['Company']})
  Rep: ${d.json['Sales Rep']}
  Score: ${d.json['Deal Score']}/100
  Risks: ${d.json['Risks']}
  Days Since Call: ${d.json['Days Since Call']}
`).join('\n')
    : '\n- None';

return [
  {
    json: {
      subject: `🚨 Weekly At-Risk Deals Report – ${items.length} Deals Reviewed`,
      body: `Weekly At-Risk Deals Report
Generated: ${reportDate}

═══════════════════════════════════════

🔴 URGENT ACTION REQUIRED (${urgentDeals.length} deals):
${formatDeals(urgentDeals)}

⚠️ REQUIRES ATTENTION (${attentionDeals.length} deals):
${formatDeals(attentionDeals)}

═══════════════════════════════════════

Review full analysis in:
Sales Intelligence Hub → Weekly Risk Report

Action Required:
• Follow up on urgent deals within 24 hours
• Monitor attention-level deals and reassess next week
`
    }
  }
];

const items = $input.all();

// Define today explicitly (fixes your error)
const today = new Date().toISOString().slice(0, 10);

// Extract all valid call dates (YYYY-MM-DD)
const dates = items
  .map(item => item.json['Call Date'])
  .filter(Boolean)
  .map(d => d.split(' ')[0]);

// If no dates exist, stop safely
if (dates.length === 0) {
  return [];
}

// Use latest date from dataset (best practice)
const latestDate = dates.sort().pop();

// Filter calls for that date
const todaysCalls = items.filter(item =>
  item.json['Call Date']?.startsWith(latestDate)
);

// ---------- Metrics ----------

// Average deal score
const scores = todaysCalls
  .map(c => Number(c.json['Deal Score']))
  .filter(n => !isNaN(n));

const avgScore = scores.length
  ? Math.round(scores.reduce((a, b) => a + b, 0) / scores.length)
  : 0;

// High intent deals
const highIntentCount = todaysCalls.filter(
  c => (c.json['Intent Level'] || '').toLowerCase() === 'high'
).length;

// At-risk deals
const atRiskCount = todaysCalls.filter(c => {
  const risks = (c.json['Risks'] || '').trim().toLowerCase();
  return risks && !['none', 'none identified', 'n/a'].includes(risks);
}).length;

// Top objection
const objectionMap = {};

todaysCalls.forEach(call => {
  const objections = call.json['Objections'];
  if (!objections) return;

  objections.split(';').forEach(o => {
    const cleaned = o.trim();
    if (!cleaned) return;
    objectionMap[cleaned] = (objectionMap[cleaned] || 0) + 1;
  });
});

const topObjection =
  Object.entries(objectionMap)
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'None';

// Best performing rep
const repScores = {};

todaysCalls.forEach(call => {
  const rep = call.json['Sales Rep'] || 'Unknown';
  const score = Number(call.json['Deal Score']);
  if (isNaN(score)) return;

  if (!repScores[rep]) repScores[rep] = [];
  repScores[rep].push(score);
});

const bestRep =
  Object.entries(repScores)
    .map(([rep, scores]) => ({
      rep,
      avg: scores.reduce((a, b) => a + b, 0) / scores.length
    }))
    .sort((a, b) => b.avg - a.avg)[0]?.rep || 'N/A';

// ---------- Output ----------
return [
  {
    json: {
      report_date: latestDate,
      system_today: today,
      total_calls_analyzed: todaysCalls.length,
      avg_deal_score: avgScore,
      high_intent_count: highIntentCount,
      at_risk_deals: atRiskCount,
      top_objection: topObjection,
      best_performing_rep: bestRep,
      generated_at: new Date().toISOString().slice(0, 19).replace('T', ' ')
    }
  }
];

