// Get raw AI output string
const rawOutput = $input.item.json.output || '';

// Remove ```json and ``` wrappers safely
const cleaned = rawOutput
  .replace(/```json/i, '')
  .replace(/```/g, '')
  .trim();

// Parse JSON
let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse AI JSON output');
}

// Return structured result
return {
  json: {
    call_summary: parsed.call_summary || '',
    intent_level: parsed.intent_level || '',
    buying_signals: Array.isArray(parsed.buying_signals)
      ? parsed.buying_signals.join('; ')
      : '',
    objections: Array.isArray(parsed.objections)
      ? parsed.objections.join('; ')
      : '',
    risks: Array.isArray(parsed.risks)
      ? parsed.risks.join('; ')
      : '',
    sentiment: parsed.sentiment || '',
    deal_score: parsed.deal_score || 0,
    recommended_action: parsed.recommended_action || '',
    follow_up_points: Array.isArray(parsed.follow_up_points)
      ? parsed.follow_up_points.join('; ')
      : ''
  }
};

